    fetch('https://cdn.jsdelivr.net/gh/ssd-secure-disclosure/challenges/chrome-ad-heavy/big.bin').then(response => {
        return response.text();
    }).then(response => {
        output.innerText = 'Response: '+response.substr(0,100)+'... (total length: '+response.length+')';
    });
}
