// shared-worker.js snippet
self.onconnect = (event) => {
    var port = event.ports[0];
    port.onmessage = (event) => {
        if (event.data.fetchUrl) {
            var fetchUrl = event.data.fetchUrl;
            fetch(fetchUrl).then(response => response.text()).then(data => {
                port.postMessage({ fetchUrl: fetchUrl, fetchResponse: data });
            });
        }
    }
}
